@app.route('/survey/create', methods=['GET', 'POST'])
@login_required
def create_survey():
    form = SurveyForm()
    if form.validate_on_submit():
        survey = Survey()

        # Remplir les champs du survey à partir du formulaire
        for field in form:
            if field.name != 'csrf_token' and field.name not in ['photo_batiment', 'photo_environ']:
                setattr(survey, field.name, field.data)

        # Traiter les photos
        if form.photo_batiment.data:
            filename = secure_filename(f"{datetime.now().strftime('%Y%m%d%H%M%S')}_batiment.jpg")
            filepath = os.path.join(current_app.config['UPLOAD_FOLDER'], filename)
            form.photo_batiment.data.save(filepath)
            survey.photo_batiment = filename

        if form.photo_environ.data:
            filename = secure_filename(f"{datetime.now().strftime('%Y%m%d%H%M%S')}_environ.jpg")
            filepath = os.path.join(current_app.config['UPLOAD_FOLDER'], filename)
            form.photo_environ.data.save(filepath)
            survey.photo_environ = filename

        # Ajouter le technicien
        survey.technicien_id = current_user.id

        try:
            db.session.add(survey)
            db.session.commit()
            flash('Survey enregistré avec succès', 'success')
            return redirect(url_for('list_surveys'))
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur lors de l\'enregistrement du survey: {str(e)}', 'error')

    return render_template('survey_form.html', form=form)

@app.route('/surveys')
@login_required
