@app.route('/dashboard')
@login_required
def dashboard():
    if current_user.role == 'chef_pur':
        performance_data = get_performance_data()
        return render_template('dashboard_chef_pur.html', 
                             stats=get_chef_pur_stats(), 
                             performance_data=performance_data,
                             zones=performance_data.get('zones', []),
                             pilots=performance_data.get('pilots', [])
                            )
    elif current_user.role == 'chef_pilote':
        return render_template('dashboard_chef_pilote.html', 
                             stats=get_chef_pilote_stats(current_user.service))
    elif current_user.role == 'chef_zone':
        stats=get_chef_zone_stats(current_user.zone)
        stats_pur=get_chef_pur_stats(zone=current_user.zone)
        stats_pur['performance_data'] = get_performance_data(zone=current_user.zone)
        return render_template('dashboard_chef_zone.html', 
                             stats=stats,
                             stats_pur=stats_pur)
    elif current_user.role == 'technicien':
        return render_template('dashboard_technicien.html', 
                             interventions=get_technicien_interventions(current_user.id))
    else:
        flash('Rôle utilisateur non reconnu.', 'error')
        return redirect(url_for('logout'))

@app.route('/import-demandes', methods=['GET', 'POST'])
@login_required
def import_demandes():
    if current_user.role not in ['chef_pur', 'chef_pilote', 'chef_zone']:
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))

    # Préremplir le service pour chef_pilote, sinon laisser le choix
    default_service = current_user.service if current_user.role == 'chef_pilote' else None
    form = ImportDemandesForm(default_service=default_service)

    if form.validate_on_submit():
        try:
            fichier = form.fichier_excel.data
            filename = secure_filename(fichier.filename)
            filepath = os.path.join(current_app.config['UPLOAD_FOLDER'], filename)
            fichier.save(filepath)

            # Traitement du fichier Excel
            result = process_excel_file(filepath, form.service.data, current_user.id)

            if result['success']:
                flash(f"Import réussi: {result['nb_lignes']} demandes importées.", 'success')
            else:
                flash(f"Erreur lors de l'import: {result['error']}", 'error')

        except Exception as e:
            flash(f'Erreur lors du traitement du fichier: {str(e)}', 'error')

    # Récupérer l'historique des imports
    imports = FichierImport.query.filter_by(importe_par=current_user.id).order_by(
        FichierImport.date_import.desc()).limit(10).all()

    return render_template('import_demandes.html', form=form, imports=imports)

