@app.route('/add-membre-equipe/<int:equipe_id>', methods=['POST'])
@login_required
def add_membre_equipe(equipe_id):
    if current_user.role != 'chef_zone':
        return jsonify({'success': False, 'error': 'Accès non autorisé'}), 403

    try:
        equipe = Equipe.query.get(equipe_id)
        if not equipe or equipe.chef_zone_id != current_user.id:
            return jsonify({'success': False, 'error': 'Équipe non trouvée'}), 404

        data = request.get_json() or {}
        nom = (data.get('nom') or '').strip()
        prenom = (data.get('prenom') or '').strip()
        telephone = (data.get('telephone') or '').strip()
        type_membre = (data.get('type_membre') or '').strip()
        technicien_id = data.get('technicien_id') or None

        # Vérification des champs obligatoires
        if not nom or not prenom or not telephone or not type_membre:
            return jsonify({'success': False, 'error': 'Tous les champs sont obligatoires.'}), 400

        membre = MembreEquipe(
            equipe_id=equipe_id,
            nom=nom,
            prenom=prenom,
            telephone=telephone,
            type_membre=type_membre,
            technicien_id=technicien_id if technicien_id else None
        )

        db.session.add(membre)
        db.session.commit()

        return jsonify({'success': True, 'message': 'Membre ajouté avec succès', 'membre_id': membre.id})

    except Exception as e:
        db.session.rollback()
        import traceback
        print('Erreur lors de l\'ajout du membre:', str(e))
        traceback.print_exc()
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/remove-membre-equipe/<int:membre_id>', methods=['DELETE'])
