@app.route('/intervention-history')
@login_required
def intervention_history():
    # Filtrer selon le rôle - requêtes simplifiées pour éviter les erreurs de join
    if current_user.role == 'chef_pur':
        interventions = Intervention.query.order_by(Intervention.date_debut.desc()).all()
    elif current_user.role == 'chef_pilote':
        # Récupérer les IDs des demandes du service
        demande_ids = [d.id for d in DemandeIntervention.query.filter_by(service=current_user.service).all()]
        interventions = Intervention.query.filter(Intervention.demande_id.in_(demande_ids)).order_by(
            Intervention.date_debut.desc()).all()
    elif current_user.role == 'chef_zone':
        # Récupérer les IDs des techniciens de la zone
        technicien_ids = [u.id for u in User.query.filter_by(role='technicien', zone=current_user.zone).all()]
        interventions = Intervention.query.filter(Intervention.technicien_id.in_(technicien_ids)).order_by(
            Intervention.date_debut.desc()).all()
    elif current_user.role == 'technicien':
        interventions = Intervention.query.filter_by(
            technicien_id=current_user.id
        ).order_by(Intervention.date_debut.desc()).all()
    else:
        interventions = []
    # Ajoute photos_list à chaque intervention
    for intervention in interventions:
        try:
            intervention.photos_list = json.loads(intervention.photos) if intervention.photos else []
        except Exception:
            intervention.photos_list = []

    return render_template('intervention_history.html', interventions=interventions)

