            return jsonify({'success': False, 'error': 'Valeur du statut manquante'}), 400
        equipe.actif = bool(actif)
        db.session.commit()
        return jsonify({'success': True})
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500       

