    if current_user.role != 'chef_zone':
        return jsonify({'error': 'Access denied'}), 403

    data = request.get_json()
    team_ids = data.get('team_ids', [])

    if not team_ids:
        return jsonify({
            'success': False,
            'error': 'Aucune équipe sélectionnée'
        }), 400

    today = datetime.now().date()

    try:
        # Get the specified teams that belong to this chef zone and are currently unpublished
        teams_to_publish = Equipe.query.filter(
            Equipe.id.in_(team_ids),
            Equipe.chef_zone_id == current_user.id,
            Equipe.zone == current_user.zone,
            Equipe.actif == True,
            Equipe.publie == False
        ).all()

        published_count = 0
        for team in teams_to_publish:
            team.publie = True
            team.date_publication = today
            published_count += 1

        db.session.commit()

        return jsonify({
            'success': True,
            'published_count': published_count,
            'message': f'{published_count} équipe(s) sélectionnée(s) publiée(s) avec succès'
        })

    except Exception as e:
        db.session.rollback()
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

