@app.route('/intervention/reject', methods=['POST'])
@login_required
def reject_intervention():
    data = request.get_json()
    intervention_id = data.get('intervention_id')
    motif = data.get('motif', '').strip()

    if not intervention_id or not motif:
        return jsonify({'success': False, 'message': 'Motif obligatoire.'}), 400

    intervention = Intervention.query.get(intervention_id)
    if not intervention:
        return jsonify({'success': False, 'message': 'Intervention introuvable.'}), 404

    # Vérifie que l'utilisateur est bien le technicien affecté
    if intervention.technicien_id != current_user.id:
        return jsonify({'success': False, 'message': 'Non autorisé.'}), 403

    # Met à jour le statut et le motif
    intervention.statut = 'rejete'
    intervention.motif_rejet = motif
    # Mettre à jour le statut de la demande liée
    if intervention.demande:
        intervention.demande.statut = 'a_reaffecter'
    db.session.commit()

    # Notifie le chef pilote (exemple simple, adapte selon ton système)
    notif = NotificationSMS(
        technicien_id=intervention.chef_pilote_id,  # À adapter selon ton modèle
        message=f"Intervention #{intervention.id} rejetée par {current_user.nom} : {motif}",
        type_notification='urgent'
    ) 
    db.session.add(notif)
    db.session.commit()

    # Envoi mail au chef_pur, chef_zone et chef_pilote
    destinataires = []
    demande = intervention.demande
    if demande:
        chef_pur = User.query.filter_by(role='chef_pur').first()
        if chef_pur and chef_pur.email:
            destinataires.append(chef_pur.email)
        if demande.zone:
            chef_zone = User.query.filter_by(role='chef_zone', zone=demande.zone).first()
            if chef_zone and chef_zone.email:
                destinataires.append(chef_zone.email)
        if demande.service:
            chef_pilote = User.query.filter_by(role='chef_pilote', service=demande.service).first()
            if chef_pilote and chef_pilote.email:
                destinataires.append(chef_pilote.email)
        technicien_nom = f"{current_user.nom} {current_user.prenom}"
        equipe_nom = ""
        if intervention.equipe_id:
            equipe = Equipe.query.get(intervention.equipe_id)
            equipe_nom = equipe.nom_equipe if equipe else ""
        subject = "Intervention rejetée"
        body = f"""Bonjour,\n\nL'intervention #{intervention.id} a été rejetée par le technicien.\n
        ND : {demande.nd}\nClient : {demande.nom_client} {demande.prenom_client}\nZone : {demande.zone}\nService : {demande.service}\n
        Technicien : {technicien_nom}\nÉquipe : {equipe_nom}\nMotif du rejet : {motif}\n
        Merci de vous connecter à Sofatelcom pour réaffecter la demande."""
        if destinataires:
            send_email(subject, destinataires, body=body)
    return jsonify({'success': True})  

@app.route('/api/stats/performance')
@login_required
def api_stats_performance():
    if current_user.role != 'chef_pur':
        return jsonify({'error': 'Accès refusé'}), 403

    # Techniciens principaux (un par équipe)
    technicians = []
    for equipe in Equipe.query.filter_by(actif=True).all():
        principal = MembreEquipe.query.filter_by(equipe_id=equipe.id, type_membre='technicien').first()
        if principal:
            validated_count = Intervention.query.filter_by(technicien_id=principal.technicien_id, statut='termine').count()
            technicians.append({
                'name': f"{principal.nom} {principal.prenom}",
                'validated': validated_count,
                'equipe': equipe.nom_equipe
            })

    # Équipes (technicien principal + accompagnants)
    teams = []
    for equipe in Equipe.query.filter_by(actif=True).all():
        validated_count = Intervention.query.filter_by(equipe_id=equipe.id, statut='valide').count()
        principal = MembreEquipe.query.filter_by(equipe_id=equipe.id, type_membre='technicien').first()
        accompagnants = MembreEquipe.query.filter_by(equipe_id=equipe.id, type_membre='accompagnant').all()
        nb_accompagnants = MembreEquipe.query.filter_by(equipe_id=equipe.id, type_membre='accompagnant').count()
        teams.append({
            'name': equipe.nom_equipe,
            'validated': validated_count,
            'principal': f"{principal.nom} {principal.prenom}" if principal else 'N/A',
            'accompagnants': nb_accompagnants,
            'accompagnant_names': ', '.join([f"{m.nom} {m.prenom}" for m in accompagnants]) if accompagnants else 'Aucun'
        })

    # Chefs pilotes (demandes importées, dispatchées, interventions validées)
    pilots = []
    for chef_pilote in User.query.filter_by(role='chef_pilote').all():
        demandes_importees = FichierImport.query.filter_by(importe_par=chef_pilote.id).count()
        demandes_dispatch = DemandeIntervention.query.filter_by(service=chef_pilote.service).filter(DemandeIntervention.statut.in_(['affecte', 'en_cours', 'valide'])).count()
        demande_ids = [d.id for d in DemandeIntervention.query.filter_by(service=chef_pilote.service).all()]
        interventions_validees = Intervention.query.filter(
            Intervention.demande_id.in_(demande_ids),
            Intervention.statut == 'valide'
        ).count()
        pilots.append({
            'name': chef_pilote.nom + ' ' + chef_pilote.prenom,
            'service': chef_pilote.service,
            'imported': demandes_importees,
            'dispatched': demandes_dispatch,
            'validated': interventions_validees
        })

    # Chefs zones (équipes créées et publiées aujourd'hui)
    zones = []
    today = date.today()
    for chef_zone in User.query.filter_by(role='chef_zone').all():
        chef_zone_name = f"{chef_zone.nom} {chef_zone.prenom}"
        # Équipes créées et publiées
        equipes_creees = Equipe.query.filter_by(chef_zone_id=chef_zone.id).count()
        equipes_publiees = Equipe.query.filter_by(chef_zone_id=chef_zone.id, date_publication=today, publie=True).count()
        # Demandes affectées (interventions en cours ou terminées)
        demandes_affectees = Intervention.query.join(User, Intervention.technicien_id == User.id)\
            .filter(User.zone == chef_zone.zone, Intervention.statut.in_(['en_cours', 'termine', 'valide'])).count()
        # Demandes validées (interventions validées)
        demandes_validees = Intervention.query.join(User, Intervention.technicien_id == User.id)\
            .filter(User.zone == chef_zone.zone, Intervention.statut == 'valide').count()
        zones.append({
            'name': chef_zone.zone,
            'chef_zone': chef_zone_name,
            'created': equipes_creees,
            'published': equipes_publiees,
            'affected': demandes_affectees,
            'validated': demandes_validees
        })

    return jsonify({
        'technicians': technicians,
        'teams': teams,
        'zones': zones,
        'pilots': pilots
    })

@app.route('/validate_interventions')
@login_required
def validate_interventions():
    if current_user.role not in ['chef_pur', 'chef_pilote', 'chef_zone']:
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))

    # Filtrer les interventions selon le rôle de l'utilisateur
    query = Intervention.query.filter_by(statut='termine')

    if current_user.role == 'chef_pilote' and current_user.service:
        # Filtrer par service via la demande d'intervention
        query = query.join(DemandeIntervention).filter_by(service=current_user.service)
    elif current_user.role == 'chef_zone' and current_user.zone:
        # Filtrer par zone via le technicien
        query = query.join(User, Intervention.technicien_id == User.id).filter_by(zone=current_user.zone)

    interventions = query.order_by(Intervention.date_fin.desc()).all()

    return render_template('validate_interventions.html', interventions=interventions)

@app.route('/validate_intervention_action/<int:intervention_id>', methods=['POST'])
@login_required
def validate_intervention_action(intervention_id):
    if current_user.role not in ['chef_pur', 'chef_pilote', 'chef_zone']:
        return jsonify({'success': False, 'error': 'Accès non autorisé'})

    intervention = Intervention.query.get_or_404(intervention_id)

    # Vérifications d'autorisation selon le rôle
    if current_user.role == 'chef_pilote' and current_user.service:
        if not intervention.demande or intervention.demande.service != current_user.service:
            return jsonify({'success': False, 'error': 'Intervention hors de votre service'})
    elif current_user.role == 'chef_zone' and current_user.zone:
        if not intervention.technicien_user or intervention.technicien_user.zone != current_user.zone:
            return jsonify({'success': False, 'error': 'Intervention hors de votre zone'})

    try:
        data = request.get_json()
        action = data.get('action')  # 'validate' ou 'reject'
        commentaire = data.get('commentaire', '')

        if action == 'validate':
            intervention.statut = 'valide'
            intervention.date_validation = datetime.now()
            intervention.valide_par = current_user.id
            intervention.commentaire_validation = commentaire
        elif action == 'reject':
            intervention.statut = 'rejete'
            intervention.date_validation = datetime.now()
            intervention.valide_par = current_user.id
            intervention.motif_rejet = commentaire
            # Remettre la demande en statut à réaffecter
            if intervention.demande:
                intervention.demande.statut = 'a_reaffecter'
        else:
            return jsonify({'success': False, 'error': 'Action non reconnue'})

        db.session.commit()
        return jsonify({'success': True, 'message': 'Intervention traitée avec succès'})

    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)})

# Routes pour la gestion des utilisateurs
@app.route('/create-user', methods=['GET', 'POST'])
@login_required
def create_user():
    if current_user.role != 'chef_pur':
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))

    form = CreateUserForm()
    if form.validate_on_submit():
        try:
            # Vérifier si l'utilisateur existe déjà
            existing_user = User.query.filter(
                (User.username == form.username.data) | 
                (User.email == form.email.data)
            ).first()

            if existing_user:
                flash('Un utilisateur avec ce nom d\'utilisateur ou cette adresse email existe déjà.', 'error')
                return render_template('create_user.html', form=form)

            # Créer le nouvel utilisateur
            new_user = User(
                username=form.username.data,
                email=form.email.data,
                password_hash=generate_password_hash(form.password.data),
                role=form.role.data,
                nom=form.nom.data,
                prenom=form.prenom.data,
                telephone=form.telephone.data,
                zone=form.zone.data if form.zone.data else None,
                commune=form.commune.data if form.commune.data else None,
                quartier=form.quartier.data if form.quartier.data else None,
                service=form.service.data if form.service.data else None,
                technologies=form.technologies.data if form.technologies.data else None
            )

            db.session.add(new_user)
            db.session.commit()

            flash(f'Utilisateur {new_user.username} créé avec succès!', 'success')
            return redirect(url_for('manage_users'))

        except Exception as e:
            db.session.rollback()
            flash(f'Erreur lors de la création de l\'utilisateur: {str(e)}', 'error')

    return render_template('create_user.html', form=form)

