@app.route('/edit-user/<int:user_id>', methods=['GET', 'POST'])
@login_required
def edit_user(user_id):
    if current_user.role != 'chef_pur':
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))

    user = User.query.get_or_404(user_id)
    form = EditUserForm(obj=user)

    if form.validate_on_submit():
        try:
            # Vérifier les conflits d'username/email avec d'autres utilisateurs
            existing_user = User.query.filter(
                User.id != user_id,
                (User.username == form.username.data) | 
                (User.email == form.email.data)
            ).first()

            if existing_user:
                flash('Un autre utilisateur avec ce nom d\'utilisateur ou cette adresse email existe déjà.', 'error')
                return render_template('edit_user.html', form=form, user=user)

            # Mettre à jour les informations
            user.username = form.username.data
            user.email = form.email.data
            user.role = form.role.data
            user.nom = form.nom.data
            user.prenom = form.prenom.data
            user.telephone = form.telephone.data
            user.zone = form.zone.data if form.zone.data else None
            user.commune = form.commune.data if form.commune.data else None
            user.quartier = form.quartier.data if form.quartier.data else None
            user.service = form.service.data if form.service.data else None
            user.technologies = form.technologies.data if form.technologies.data else None
            user.actif = form.actif.data

            # Changer le mot de passe si fourni
            if form.new_password.data:
                user.password_hash = generate_password_hash(form.new_password.data)

            db.session.commit()

            flash(f'Utilisateur {user.username} mis à jour avec succès!', 'success')
            return redirect(url_for('manage_users'))

        except Exception as e:
            db.session.rollback()
            flash(f'Erreur lors de la mise à jour: {str(e)}', 'error')

    return render_template('edit_user.html', form=form, user=user)

@app.route('/delete-user/<int:user_id>', methods=['POST'])
@login_required
def delete_user(user_id):
    if current_user.role != 'chef_pur':
        return jsonify({'success': False, 'error': 'Accès non autorisé'}), 403

    if user_id == current_user.id:
        return jsonify({'success': False, 'error': 'Vous ne pouvez pas supprimer votre propre compte'}), 400

    try:
        user = User.query.get_or_404(user_id)

        # Vérifier s'il y a des dépendances (interventions, équipes créées, etc.)
        interventions_count = DemandeIntervention.query.filter_by(technicien_id=user_id).count()
        equipes_count = Equipe.query.filter_by(chef_zone_id=user_id).count()

        if interventions_count > 0 or equipes_count > 0:
            return jsonify({
                'success': False, 
                'error': f'Impossible de supprimer: cet utilisateur a {interventions_count} intervention(s) et {equipes_count} équipe(s) associée(s)'
            }), 400

        db.session.delete(user)
        db.session.commit()

        return jsonify({'success': True, 'message': f'Utilisateur {user.username} supprimé avec succès'})

    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/toggle-user-status/<int:user_id>', methods=['POST'])
@login_required
def toggle_user_status(user_id):
    if current_user.role != 'chef_pur':
        return jsonify({'success': False, 'error': 'Accès non autorisé'}), 403

    if user_id == current_user.id:
        return jsonify({'success': False, 'error': 'Vous ne pouvez pas désactiver votre propre compte'}), 400

    try:
        user = User.query.get_or_404(user_id)
        data = request.get_json() or {}
        actif = data.get('actif')

        if actif is None:
            return jsonify({'success': False, 'error': 'Statut manquant'}), 400

        user.actif = bool(actif)
        db.session.commit()

        status_text = "activé" if user.actif else "désactivé"
        return jsonify({'success': True, 'message': f'Utilisateur {status_text} avec succès'})

    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500

