/**
 * Sofatelcom PUR - Module de Gestion des Équipes
 * Fonctionnalités pour la création et gestion des équipes d'intervention
 */

// État du module équipes
const TeamsModule = {
    currentEquipe: null,
    membres: [],
    availableTechniciens: [],
    config: {
        maxMembresParEquipe: 10,
        technologiesDisponibles: ['Fibre', 'Cuivre', '5G'],
        zonesDisponibles: ['Dakar', 'Mbour', 'Kaolack', 'Autres'],
        servicesDisponibles: ['SAV', 'Production']
    }
};

// Initialisation du module équipes
document.addEventListener('DOMContentLoaded', function() {
    if (document.querySelector('#createTeamForm') || document.querySelector('#addMembreForm')) {
        initializeTeams();
    }
});

function initializeTeams() {
    loadAvailableTechniciens();
    setupTeamEventListeners();
    initializeFormValidation();
    setupAutoGeneration();
}

// Chargement des techniciens disponibles
function loadAvailableTechniciens() {
    const technicienSelects = document.querySelectorAll('select[id*="technicien"]');
    technicienSelects.forEach(select => {
        Array.from(select.options).forEach(option => {
            if (option.value) {
                TeamsModule.availableTechniciens.push({
                    id: option.value,
                    nom: option.dataset.nom || '',
                    prenom: option.dataset.prenom || '',
                    telephone: option.dataset.telephone || '',
                    technologies: option.dataset.technologies || '',
                    zone: option.dataset.zone || ''
                });
            }
        });
    });
}

// Configuration des écouteurs d'événements
function setupTeamEventListeners() {
    // Génération automatique du nom d'équipe
    ['zone', 'technologies', 'service'].forEach(fieldId => {
        const field = document.getElementById(fieldId);
        if (field) field.addEventListener('change', generateTeamName);
    });

    // Type de membre (technicien/accompagnant)
    const typeMembre = document.getElementById('type_membre');
    if (typeMembre) {
        typeMembre.addEventListener('change', toggleTechnicienSelect);
    }

    // Sélection de technicien référencé
    const technicienSelect = document.getElementById('technicien_id');
    if (technicienSelect) {
        technicienSelect.addEventListener('change', autoFillMemberInfo);
    }

    // Validation de téléphone en temps réel
    const telephoneInput = document.getElementById('telephone');
    if (telephoneInput) {
        telephoneInput.addEventListener('input', validatePhoneNumber);
    }
}

// Initialisation de la validation des formulaires
function initializeFormValidation() {
    // Validation du formulaire de création d'équipe
    const createForm = document.getElementById('createTeamForm');
    if (createForm) {
        createForm.addEventListener('submit', validateTeamForm);
    }

    // Validation du formulaire d'ajout de membre
    const addMembreForm = document.getElementById('addMembreForm');
    if (addMembreForm) {
        addMembreForm.addEventListener('submit', validateMembreForm);
    }
}

// Configuration de la génération automatique
function setupAutoGeneration() {
    const dateInput = document.getElementById('date_creation');
    if (dateInput && !dateInput.value) {
        const today = new Date().toISOString().split('T')[0];
        dateInput.value = today;
    }
    const zoneSelect = document.getElementById('zone');
    const chefZone = document.body.dataset.userZone;
    if (zoneSelect && chefZone) {
        zoneSelect.value = chefZone;
    }
    generateTeamName();
}

// Génération automatique du nom d'équipe
function generateTeamName() {
    const zone = document.getElementById('zone')?.value;
    const technologies = document.getElementById('technologies')?.value;
    const service = document.getElementById('service')?.value;
    const nameInput = document.getElementById('nom_equipe');
    if (!zone || !technologies || !service || !nameInput) return;
    if (nameInput.value && !nameInput.dataset.autoGenerated) return;
    const date = new Date().toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit' }).replace('/', '');
    const techAbbr = technologies.includes(',') ? 'Multi' : technologies.substring(0, 4);
    const serviceAbbr = service === 'Production' ? 'Prod' : service;
    const suggestion = `Équipe ${techAbbr} ${zone} ${serviceAbbr} ${date}`;
    nameInput.value = suggestion;
    nameInput.dataset.autoGenerated = 'true';
    nameInput.addEventListener('input', function() {
        this.dataset.autoGenerated = 'false';
    }, { once: true });
}

// Basculement de l'affichage de sélection de technicien

function toggleTechnicienSelect() {
    const type = document.getElementById('type_membre').value;
    const container = document.getElementById('technicienSelectContainer');
    if (!container) return;
    if (type === 'technicien') {
        container.style.display = 'block';
    } else {
        container.style.display = 'none';
        const technicienSelect = document.getElementById('technicien_id');
        // On ne vide les champs que si un technicien référencé était sélectionné
        if (technicienSelect && technicienSelect.value) {
            technicienSelect.value = '';
            clearMemberFormFields();
        }
    }
}

// Auto-remplissage lors de la sélection d'un technicien référencé
function autoFillMemberInfo() {
    const technicienSelect = document.getElementById('technicien_id');
    if (!technicienSelect) return;
    const selectedOption = technicienSelect.options[technicienSelect.selectedIndex];
    if (selectedOption.value) {
        fillMemberFields({
            nom: selectedOption.dataset.nom,
            prenom: selectedOption.dataset.prenom,
            telephone: selectedOption.dataset.telephone
        }, true);
        showTechnicienInfo(selectedOption);
    } else {
        clearMemberFormFields();
    }
}

// Remplissage des champs de membre
function fillMemberFields(data, readonly = false) {
    ['nom', 'prenom', 'telephone'].forEach(field => {
        const input = document.getElementById(field);
        if (input) {
            input.value = data[field] || '';
            input.readOnly = readonly;
            if (readonly) input.classList.add('bg-light');
            else input.classList.remove('bg-light');
        }
    });
}

// Nettoyage des champs de membre
function clearMemberFormFields() {
    fillMemberFields({ nom: '', prenom: '', telephone: '' }, false);
    hideTechnicienInfo();
}

// Affichage des informations du technicien sélectionné
function showTechnicienInfo(option) {
    let infoElement = document.getElementById('technicien-info');
    if (!infoElement) {
        infoElement = document.createElement('div');
        infoElement.id = 'technicien-info';
        infoElement.className = 'alert alert-info mt-2';
        const container = document.getElementById('technicienSelectContainer');
        if (container) container.appendChild(infoElement);
    }
    const technologies = option.dataset.technologies || 'Non spécifiées';
    const zone = option.dataset.zone || 'Non spécifiée';
    infoElement.innerHTML = `
        <small>
            <i data-feather="info" class="me-1"></i>
            <strong>Spécialités:</strong> ${technologies} | 
            <strong>Zone:</strong> ${zone}
        </small>
    `;
    feather.replace();
}

// Masquage des informations du technicien
function hideTechnicienInfo() {
    const infoElement = document.getElementById('technicien-info');
    if (infoElement) infoElement.remove();
}

// Validation du numéro de téléphone
function validatePhoneNumber() {
    const input = document.getElementById('telephone');
    if (!input) return;
    const value = input.value;
    const isValid = /^221[0-9]{9}$/.test(value);
    input.classList.remove('is-valid', 'is-invalid');
    if (value.length > 0) input.classList.add(isValid ? 'is-valid' : 'is-invalid');
    updatePhoneValidationMessage(input, isValid, value.length > 0);
}

function updatePhoneValidationMessage(input, isValid, hasValue) {
    let feedbackElement = input.parentNode.querySelector('.feedback-phone');
    if (!feedbackElement) {
        feedbackElement = document.createElement('div');
        feedbackElement.className = 'feedback-phone small mt-1';
        input.parentNode.appendChild(feedbackElement);
    }
    if (!hasValue) {
        feedbackElement.textContent = '';
        feedbackElement.className = 'feedback-phone small mt-1';
    } else if (isValid) {
        feedbackElement.textContent = '✓ Numéro valide';
        feedbackElement.className = 'feedback-phone small mt-1 text-success';
    } else {
        feedbackElement.textContent = '✗ Format: 221xxxxxxxxx (12 chiffres)';
        feedbackElement.className = 'feedback-phone small mt-1 text-danger';
    }
}

// Validation du formulaire d'équipe
function validateTeamForm(event) {
    event.preventDefault();
    const form = event.target;
    const errors = [];
    [
        { id: 'nom_equipe', name: 'Nom de l\'équipe' },
        { id: 'date_creation', name: 'Date de création' },
        { id: 'zone', name: 'Zone' },
        { id: 'technologies', name: 'Technologies' },
        { id: 'service', name: 'Service' }
    ].forEach(field => {
        const input = document.getElementById(field.id);
        if (input && !input.value.trim()) {
            errors.push(`${field.name} est obligatoire`);
            input.classList.add('is-invalid');
        } else if (input) {
            input.classList.remove('is-invalid');
        }
    });
    const dateInput = document.getElementById('date_creation');
    if (dateInput && dateInput.value) {
        const selectedDate = new Date(dateInput.value);
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        if (selectedDate < today) {
            errors.push('La date de création ne peut pas être dans le passé');
            dateInput.classList.add('is-invalid');
        }
    }
    const nomEquipe = document.getElementById('nom_equipe')?.value.trim();
    if (nomEquipe) {
        checkTeamNameUniqueness(nomEquipe).then(isUnique => {
            if (!isUnique) {
                errors.push('Ce nom d\'équipe existe déjà pour aujourd\'hui');
                document.getElementById('nom_equipe').classList.add('is-invalid');
            }
            finalizeTeamValidation(form, errors);
        });
    } else {
        finalizeTeamValidation(form, errors);
    }
}

function finalizeTeamValidation(form, errors) {
    if (errors.length > 0) {
        showValidationErrors(errors);
        return;
    }
    const nomEquipe = document.getElementById('nom_equipe').value;
    const confirmMessage = `Créer l'équipe "${nomEquipe}" ?`;
    if (confirm(confirmMessage)) {
        submitTeamForm(form);
    }
}

function checkTeamNameUniqueness(nom) {
    return fetch('/api/check-team-name', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nom_equipe: nom })
    })
    .then(response => response.json())
    .then(data => data.available)
    .catch(() => true);
}

function submitTeamForm(form) {
    const submitBtn = form.querySelector('button[type="submit"]');
    const originalText = submitBtn.innerHTML;
    submitBtn.disabled = true;
    submitBtn.innerHTML = '<i data-feather="loader" class="me-2"></i>Création...';
    form.submit();
}

// Validation du formulaire de membre
function validateMembreForm(event) {
    event.preventDefault();
    const form = event.target;
    const errors = [];
    [
        { id: 'nom', name: 'Nom' },
        { id: 'prenom', name: 'Prénom' },
        { id: 'telephone', name: 'Téléphone' },
        { id: 'type_membre', name: 'Type de membre' }
    ].forEach(field => {
        const input = document.getElementById(field.id);
        if (input && !input.value.trim()) {
            errors.push(`${field.name} est obligatoire`);
            input.classList.add('is-invalid');
        } else if (input) {
            input.classList.remove('is-invalid');
        }
    });
    const telephone = document.getElementById('telephone')?.value.trim();
    if (telephone && !/^221[0-9]{9}$/.test(telephone)) {
        errors.push('Le numéro de téléphone doit être au format 221xxxxxxxxx');
        document.getElementById('telephone').classList.add('is-invalid');
    }
    const currentMembersCount = document.querySelectorAll('#membresTableBody tr').length;
    if (currentMembersCount >= TeamsModule.config.maxMembresParEquipe) {
        errors.push(`Maximum ${TeamsModule.config.maxMembresParEquipe} membres par équipe`);
    }
    if (errors.length > 0) {
        showValidationErrors(errors);
        return;
    }
    submitMembreForm(form);
}

// Soumission du formulaire de membre
function submitMembreForm(form) {
    const formData = new FormData(form);
    const data = Object.fromEntries(formData.entries());
    data.nom = document.getElementById('nom').value;
    data.prenom = document.getElementById('prenom').value;
    data.telephone = document.getElementById('telephone').value;
    data.type_membre = document.getElementById('type_membre').value;
    const technicienSelect = document.getElementById('technicien_id');
    if (technicienSelect && technicienSelect.value) {
        data.technicien_id = technicienSelect.value;
    }
    const submitBtn = form.querySelector('button[type="submit"]');
    const originalText = submitBtn.innerHTML;
    submitBtn.disabled = true;
    submitBtn.innerHTML = '<i data-feather="loader" class="me-2"></i>Ajout...';
    const equipeId = window.equipeId || getEquipeIdFromUrl();
    fetch(`/add-membre-equipe/${equipeId}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
    })
    .then(async response => {
        const contentType = response.headers.get('content-type') || '';
        if (!response.ok) {
            let errorMsg = `Erreur HTTP: ${response.status}`;
            if (contentType.includes('application/json')) {
                const errJson = await response.json();
                errorMsg = errJson.error || errorMsg;
            }
            throw new Error(errorMsg);
        }
        if (!contentType.includes('application/json')) {
            throw new Error('La réponse du serveur n\'est pas du JSON.');
        }
        return response.json();
    })
    .then(result => {
        if (result.success) {
            showNotification(result.message, 'success');
            addMembreToTable(data);
            form.reset();
            toggleTechnicienSelect();
            updateTeamStats();
        } else {
            showNotification('Erreur: ' + (result.error || 'Erreur inconnue.'), 'error');
        }
    })
    .catch(error => {
        showNotification('Erreur lors de l\'ajout du membre: ' + error.message, 'error');
    })
    .finally(() => {
        submitBtn.disabled = false;
        submitBtn.innerHTML = originalText;
        feather.replace();
    });
}

// Ajout d'un membre au tableau
function addMembreToTable(data) {
    const tableBody = document.getElementById('membresTableBody');
    if (!tableBody) return;
    // Supprimer le message "aucun membre" si présent
    const emptyMessage = tableBody.querySelector('.text-center');
    if (emptyMessage) emptyMessage.closest('tr').remove();
    const row = document.createElement('tr');
    row.className = 'fade-in';
    const badgeClass = data.type_membre === 'technicien' ? 'primary' : 'secondary';
    const statusBadge = data.technicien_id ?
        '<span class="badge bg-success"><i data-feather="check" style="width: 12px; height: 12px;"></i> Référencé</span>' :
        '<span class="badge bg-warning"><i data-feather="user" style="width: 12px; height: 12px;"></i> Externe</span>';
    row.innerHTML = `
        <td>${data.nom}</td>
        <td>${data.prenom}</td>
        <td>
            <a href="tel:${data.telephone}" class="text-decoration-none">
                <i data-feather="phone" class="me-1" style="width: 16px; height: 16px;"></i>
                ${data.telephone}
            </a>
        </td>
        <td>
            <span class="badge bg-${badgeClass}">
                ${data.type_membre.charAt(0).toUpperCase() + data.type_membre.slice(1)}
            </span>
        </td>
        <td>${statusBadge}</td>
        <td>
            <button class="btn btn-sm btn-outline-danger" onclick="removeMembre('temp')" title="Supprimer">
                <i data-feather="trash-2" style="width: 16px; height: 16px;"></i>
            </button>
        </td>
    `;
    tableBody.appendChild(row);
    feather.replace();
    setTimeout(() => { row.classList.remove('fade-in'); }, 500);

}

// Suppression d'un membre
function removeMembre(membreId) {
    if (!confirm('Êtes-vous sûr de vouloir supprimer ce membre de l\'équipe ?')) return;
    if (membreId === 'temp') {
        showNotification('Membre supprimé (fonctionnalité à implémenter)', 'info');
        return;
    }
    fetch(`/remove-membre-equipe/${membreId}`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' }
    })
    .then(response => response.json())
    .then(result => {
        if (result.success) {
            showNotification('Membre supprimé avec succès', 'success');
            const row = document.getElementById(`membre-${membreId}`);
            if (row) {
                row.style.transition = 'all 0.3s ease';
                row.style.opacity = '0';
                row.style.transform = 'translateX(-100%)';
                setTimeout(() => {
                    row.remove();
                    updateTeamStats();
                    checkEmptyTable();
                }, 300);
            }
        } else {
            showNotification('Erreur: ' + result.error, 'error');
        }
    })
    .catch(error => {
        showNotification('Erreur lors de la suppression', 'error');
    });
}

// Vérification si le tableau est vide
function checkEmptyTable() {
    const tableBody = document.getElementById('membresTableBody');
    if (tableBody && tableBody.children.length === 0) {
        const row = document.createElement('tr');
        row.innerHTML = `
            <td colspan="6" class="text-center py-4">
                <i data-feather="users" style="width: 48px; height: 48px;" class="text-muted mb-3"></i>
                <h6 class="text-muted">Aucun membre dans l'équipe</h6>
                <p class="text-muted">Commencez par ajouter des techniciens et accompagnants</p>
            </td>
        `;
        tableBody.appendChild(row);
        feather.replace();
    }
}

// Mise à jour des statistiques de l'équipe
function updateTeamStats() {
    const tableBody = document.getElementById('membresTableBody');
    if (!tableBody) return;
    const rows = tableBody.querySelectorAll('tr:not(.text-center)');
    let totalMembres = 0;
    let techniciens = 0;
    let accompagnants = 0;
    rows.forEach(row => {
        // On ignore les lignes vides ou de message
        if (row.querySelector('td') && !row.querySelector('td').classList.contains('text-center')) {
            totalMembres++;
            const badge = row.querySelector('.badge');
            if (badge && badge.textContent.toLowerCase().includes('technicien')) techniciens++;
            else accompagnants++;
        }
    });
    // Met à jour les stats dynamiquement
    const statTotal = document.querySelector('.text-primary');
    if (statTotal) statTotal.textContent = totalMembres;
    const statTech = document.querySelector('.text-success');
    if (statTech) statTech.textContent = techniciens;
    const statAcc = document.querySelector('.text-info');
    if (statAcc) statAcc.textContent = accompagnants;
    updateStatElement('stat-total-membres', totalMembres);
    updateStatElement('stat-techniciens', techniciens);
    updateStatElement('stat-accompagnants', accompagnants);
}

function updateStatElement(className, value) {
    const element = document.querySelector(`.${className}`) || document.querySelector(`[data-stat="${className}"]`);
    if (element) {
        element.textContent = value;
        element.classList.add('pulse');
        setTimeout(() => element.classList.remove('pulse'), 600);
    }
}

function getEquipeIdFromUrl() {
    const pathParts = window.location.pathname.split('/');
    const manageIndex = pathParts.indexOf('manage-team');
    return manageIndex !== -1 && pathParts[manageIndex + 1] ? pathParts[manageIndex + 1] : null;
}

// Notifications
function showNotification(message, type = 'info') {
    const alertDiv = document.createElement('div');
    alertDiv.className = `alert alert-${type === 'error' ? 'danger' : type} alert-dismissible fade show position-fixed`;
    alertDiv.style.top = '10px';
    alertDiv.style.right = '10px';
    alertDiv.style.zIndex = '9999';
    alertDiv.innerHTML = `
        ${message}
        <button type="button" class="btn-close" data-bs-dismiss="alert"></button>
    `;
    document.body.appendChild(alertDiv);
    setTimeout(() => { alertDiv.remove(); }, 5000);
}
/**
 * Affichage des erreurs de validation
 */
function showValidationErrors(errors) {
    const errorMessage = errors.join('\n• ');
    showNotification(`Erreurs de validation :\n• ${errorMessage}`, 'error');
}
/**
 * Affichage d'erreur pour les équipes du jour
 */
function displayEquipesJourError() {
    const container = document.getElementById('equipesJour');
    if (container) {
        container.innerHTML = '<p class="text-danger small mb-0">Erreur de chargement</p>';
    }
}
/**
 * Basculement du statut d'équipe
 */
function toggleEquipeStatus(equipeId, actif) {
    const action = actif ? 'activer' : 'désactiver';
    // Vérification de l'ID
    if (!equipeId || isNaN(Number(equipeId))) {
        showNotification("ID d'équipe invalide : " + equipeId, 'error');
        return;
    }
    if (!confirm(`Êtes-vous sûr de vouloir ${action} cette équipe ?`)) {
        return;
    }
    fetch(`/toggle-equipe-status/${equipeId}`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
        },
        body: JSON.stringify({ actif: actif })
    })
    .then(async response => {
        const contentType = response.headers.get('content-type') || '';
        if (!response.ok) {
            let errorMsg = `Erreur HTTP: ${response.status}`;
            if (contentType.includes('application/json')) {
                const errJson = await response.json();
                errorMsg = errJson.error || errorMsg;
            }
            throw new Error(errorMsg);
        }
        if (!contentType.includes('application/json')) {
            throw new Error('La réponse du serveur n\'est pas du JSON.');
        }
        return response.json();
    })
    .then(result => {
        if (result.success) {
            showNotification(`Équipe ${actif ? 'activée' : 'désactivée'} avec succès`, 'success');
            setTimeout(() => location.reload(), 1500);
        } else {
            showNotification('Erreur: ' + result.error, 'error');
        }
    })
    .catch(error => {
        console.error('Erreur:', error);
        showNotification('Erreur lors de la modification du statut : ' + error.message, 'error');
    });
}
/**
 * Chargement des équipes du jour
 */
function loadEquipesJour() {
    return fetch('/api/equipes-jour')
        .then(response => response.json())
        .then(data => {
            if (data.success) {
                displayEquipesJour(data.equipes);
            } else {
                displayEquipesJourError();
            }
        })
        .catch(error => {
            console.error('Erreur:', error);
            displayEquipesJourError();
        });
}

/**
 * Affichage des équipes du jour
 */
function displayEquipesJour(equipes) {
    const container = document.getElementById('equipesJour');
    if (!container) return;

    if (equipes.length === 0) {
        container.innerHTML = '<p class="text-muted small mb-0">Aucune équipe créée aujourd\'hui</p>';
        return;
    }

    let html = '';
    equipes.forEach(equipe => {
        html += `
            <div class="border-bottom pb-2 mb-2 slide-in-left">
                <div class="d-flex justify-content-between align-items-start">
                    <div>
                        <h6 class="mb-1">${equipe.nom_equipe}</h6>
                        <small class="text-muted">
                            ${equipe.service} - ${equipe.technologies}
                            <br>
                            ${equipe.nb_membres || 0} membre(s)
                        </small>
                    </div>
                    <span class="badge bg-${equipe.actif ? 'success' : 'secondary'} small">
                        ${equipe.actif ? 'Active' : 'Inactive'}
                    </span>
                </div>
            </div>
        `;
    });

    container.innerHTML = html;
}

// Export du module pour utilisation globale
window.TeamsModule = TeamsModule;
window.generateTeamName = generateTeamName;
window.toggleTechnicienSelect = toggleTechnicienSelect;
window.removeMembre = removeMembre;
window.getEquipeIdFromUrl = getEquipeIdFromUrl;

